head.script:
let memJson = $c.data.getMemInfo();
scwin.privAdmin = $c.data.getMemInfo("privAdmin");
scwin.empNo = $c.data.getMemInfo("empNo");
scwin.userId = $c.data.getMemInfo("userId") || "";
scwin.advcdGrpCd = "";
scwin.seq = "";
scwin.advcdPrgStsCd = "";

let empNo_Yn = "";
let vEmpNo = scwin.empNo;
let RETRIEVE_AUTH = "R";

scwin.systemPathKey = "FILE_UPLOAD_SYSTEM_PATH";
scwin.systemPathVal = "/fileUpload";
scwin.argObject = "";
scwin.g_filePath = "";
scwin.g_fileName = "";
scwin.g_accdNo = "temp";
scwin.pendingImportSave = false;

scwin.onpageload = function() {
    let paramData = $p.getParameter("wframeParam") || $c.data.getParameter() || {};
    scwin.advcdGrpCd = $c.str.trim($p, paramData.advcdGrpCd || "");
    scwin.seq = $c.str.trim($p, paramData.seq || "");
    scwin.advcdPrgStsCd = $c.str.trim($p, paramData.advcdPrgStsCd || "");

    ed_hhblno.setValue(scwin.advcdGrpCd);
    scwin.f_empNo();

    if (!$c.util.isEmpty(scwin.advcdGrpCd) && !$c.util.isEmpty(scwin.seq)) {
        scwin.f_Retrieve();
    } else {
        scwin.f_clearFileList();
    }

    udc_fileUpload.setFixNum("4");
    scwin.applyUploadSubDir(scwin.advcdGrpCd, scwin.seq);
    scwin.f_CtrlStatus();
};

scwin.onUdcCompleted = function() {
    scwin.applyUploadSubDir(scwin.getCurrentAdvcdGrpCd(), scwin.seq);
    scwin.f_CtrlStatus();
};

scwin.getFileUploadScope = function() {
    if (typeof udc_fileUpload === "undefined") {
        return null;
    }

    if (typeof udc_fileUpload.getScopeWindow === "function") {
        return udc_fileUpload.getScopeWindow();
    }

    return null;
};

scwin.getCurrentAdvcdGrpCd = function() {
    if (typeof ed_hhblno !== "undefined" && typeof ed_hhblno.getValue === "function") {
        return $c.str.trim($p, ed_hhblno.getValue() || "");
    }

    return $c.str.trim($p, scwin.advcdGrpCd || "");
};

scwin.buildUploadSubDir = function(advcdGrpCd, seq) {
    if ($c.util.isEmpty(advcdGrpCd) || $c.util.isEmpty(seq)) {
        return "";
    }

    return "FM/paymgnt/advcdmgnt/AdvancedPayment/" + advcdGrpCd + "/" + seq + "/";
};

scwin.applyUploadSubDir = function(advcdGrpCd, seq) {
    if (typeof udc_fileUpload === "undefined") {
        return;
    }

    scwin.systemPathVal = scwin.buildUploadSubDir(advcdGrpCd, seq);

    if (typeof udc_fileUpload.setSubDir === "function") {
        udc_fileUpload.setSubDir(scwin.systemPathVal);
    }

    if (typeof udc_fileUpload.setSubDirYearMonthYn === "function") {
        udc_fileUpload.setSubDirYearMonthYn("N");
    }
};

scwin.applyFileUploadControlState = function(isEnabled) {
    if (typeof udc_fileUpload === "undefined") {
        return;
    }

    if (typeof btn_importFile !== "undefined" && typeof btn_importFile.setDisabled === "function") {
        btn_importFile.setDisabled(!isEnabled);
    }

    if (typeof udc_fileUpload.setFileSelectingButtonDisabled === "function") {
        udc_fileUpload.setFileSelectingButtonDisabled(!isEnabled);
    }

    if (typeof udc_fileUpload.setSaveButtonVisible === "function") {
        udc_fileUpload.setSaveButtonVisible(isEnabled ? "Y" : "N");
    }

    const uploadScope = scwin.getFileUploadScope();
    const uploadPage = uploadScope && uploadScope.$p ? uploadScope.$p : null;
    if (!uploadPage || typeof uploadPage.getComponentById !== "function") {
        return;
    }

    const addBtn = uploadPage.getComponentById("btn_fileSelecting");
    const saveBtn = uploadPage.getComponentById("btn_trigger1");
    const uploader = uploadPage.getComponentById("mpd_multiFileUpload");

    if (addBtn && typeof addBtn.setDisabled === "function") {
        addBtn.setDisabled(!isEnabled);
    }

    if (uploader && typeof uploader.setDisabled === "function") {
        uploader.setDisabled(!isEnabled);
    }

    if (saveBtn && typeof saveBtn.setDisabled === "function") {
        saveBtn.setDisabled(!isEnabled);
    }

    if (saveBtn && typeof saveBtn.show === "function" && typeof saveBtn.hide === "function") {
        if (isEnabled) {
            saveBtn.show("");
        } else {
            saveBtn.hide();
        }
    }
};

scwin.setFileUploadControlEnabled = function(isEnabled) {
    if (typeof udc_fileUpload === "undefined") {
        return;
    }

    scwin.applyFileUploadControlState(isEnabled);
    [50, 200, 500, 1000].forEach(function(delay) {
        setTimeout(function() {
            scwin.applyFileUploadControlState(isEnabled);
        }, delay);
    });
};

scwin.isEditableFileUploadStatus = function() {
    return scwin.advcdPrgStsCd !== "04";
};

scwin.f_CtrlStatus = function() {
    const hasGroupNo = !$c.util.isEmpty(scwin.getCurrentAdvcdGrpCd());
    scwin.setFileUploadControlEnabled(hasGroupNo && scwin.isEditableFileUploadStatus());
};

scwin.fileSubmit = async function() {
    let advcdGrpCd = scwin.getCurrentAdvcdGrpCd();

    if ($c.util.isEmpty(advcdGrpCd)) {
        $c.win.alert("그룹번호가 필수입니다.");
        ed_hhblno.focus();
        scwin.f_CtrlStatus();
        return;
    }

    if (!scwin.isEditableFileUploadStatus()) {
        $c.win.alert("요청/확인취소 상태에서만 파일첨부가 가능합니다.");
        scwin.f_CtrlStatus();
        return;
    }

    if (scwin.advcdPrgStsCd === "04") {
        $c.win.alert("확정상태에서는 파일첨부를 할 수 없습니다.");
        scwin.f_CtrlStatus();
        return;
    }

    if ($c.util.isEmpty(scwin.seq)) {
        $c.win.alert("순번 정보가 없습니다.");
        return;
    }

    scwin.advcdGrpCd = advcdGrpCd;
    dma_attachedFile.set("advcdGrpCd", advcdGrpCd);
    dma_attachedFile.set("seq", scwin.seq);
    scwin.applyUploadSubDir(advcdGrpCd, scwin.seq);

    ds_fileDeleteGDS.removeAll();

    let fileList = udc_fileUpload.getData() || [];
    let hasNewFile = false;
    let hasDeleteFile = false;

    for (let i = 0; i < fileList.length; i++) {
        if ($c.util.isEmpty(fileList[i].hiddenKey)) {
            hasNewFile = true;
        }

        if (fileList[i].chk == "1" && !$c.util.isEmpty(fileList[i].hiddenKey)) {
            let row = ds_fileDeleteGDS.insertRow();
            ds_fileDeleteGDS.setCellData(row, "advcdGrpCd", advcdGrpCd);
            ds_fileDeleteGDS.setCellData(row, "seq", scwin.seq);
            ds_fileDeleteGDS.setCellData(row, "fileSeq", fileList[i].hiddenKey);
            ds_fileDeleteGDS.setCellData(row, "filePath", fileList[i].FILE_STORED_PATH || "");
            hasDeleteFile = true;
        }
    }

    if (hasNewFile) {
        await udc_fileUpload.startFileUpload();
        return;
    }

    if (hasDeleteFile) {
        await $c.sbm.execute(sbm_deleteFile);
        return;
    }

    await $c.win.alert("변경된 파일이 없습니다.");
};

scwin.f_Close = function() {
    let rtnList = ds_attachedFileList.getRowJSON(ds_attachedFileList.getrowpo);
    $c.win.closePopup(rtnList);
};

scwin.f_empNo = function() {
    let grp_cd = "FI111";
    let pCode = scwin.empNo;
    let param1 = "CD as COL1, CD_NM as COL2, '' as COL3, '' as COL4, '' as COL5, '' as COL6, '' as COL7, '' as COL8, '' as COL9, '' as COL10";
    let param2 = " TB_ZZ002 ";
    let param3 = " AND GRP_CD = '" + grp_cd + "' AND USE_YN = '1' AND CD_NM = '" + pCode + "' ";
    let param4 = "CD";

    ds_empNo_condition.setJSON({
        sysCd: "CommonEBC",
        queryId: "dinymicQueryTest",
        param1: param1,
        param2: param2,
        param3: param3,
        param4: param4
    });

    $c.sbm.execute(sbm_searchEmpNo);
};

scwin.sbm_searchEmpNo_submitdone = function(e) {
    if (e.responseJSON.GAUCE) {
        ds_empNo.setJSON(e.responseJSON.GAUCE);
    }
};

scwin.btn_search_onclick = function() {
    scwin.f_Retrieve();
};

scwin.buildImportSaveRows = function() {
    ds_fileUploadGDS.removeAll();

    for (let i = 0; i < ds_importFileList.getRowCount(); i++) {
        let row = ds_fileUploadGDS.insertRow();
        ds_fileUploadGDS.setCellData(row, "advcdGrpCd", scwin.advcdGrpCd);
        ds_fileUploadGDS.setCellData(row, "seq", scwin.seq);
        ds_fileUploadGDS.setCellData(row, "fileClsCd", "");
        ds_fileUploadGDS.setCellData(row, "fileName", ds_importFileList.getCellData(i, "fileName"));
        ds_fileUploadGDS.setCellData(row, "filePath", ds_importFileList.getCellData(i, "filePath"));
        ds_fileUploadGDS.setCellData(row, "fileSize", ds_importFileList.getCellData(i, "fileSize"));
        ds_fileUploadGDS.setCellData(row, "regId", scwin.userId);
        ds_fileUploadGDS.setCellData(row, "modId", scwin.userId);
    }
};

scwin.f_ImportFile = async function() {
    let advcdGrpCd = scwin.getCurrentAdvcdGrpCd();

    if ($c.util.isEmpty(advcdGrpCd)) {
        $c.win.alert("그룹번호가 필수입니다.");
        ed_hhblno.focus();
        scwin.f_CtrlStatus();
        return;
    }

    if (!scwin.isEditableFileUploadStatus()) {
        $c.win.alert("확정상태에서는 파일 가져오기를 할 수 없습니다.");
        scwin.f_CtrlStatus();
        return;
    }

    if ($c.util.isEmpty(scwin.seq)) {
        $c.win.alert("순번 정보가 없습니다.");
        return;
    }

    if (!await $c.win.confirm("파일을 가져오시겠습니까?")) {
        return;
    }

    scwin.advcdGrpCd = advcdGrpCd;
    dma_attachedFile.set("advcdGrpCd", advcdGrpCd);
    dma_attachedFile.set("seq", scwin.seq);
    scwin.applyUploadSubDir(advcdGrpCd, scwin.seq);
    ds_importFileList.removeAll();
    $c.sbm.execute(sbm_retrieveImportFileList);
};

scwin.buildUploadFilePath = function(storedPath, storedFileName) {
    if ($c.util.isEmpty(storedPath)) {
        return storedFileName || "";
    }

    if ($c.util.isEmpty(storedFileName) || storedPath.endsWith(storedFileName)) {
        return storedPath;
    }

    if (storedPath.endsWith("/")) {
        return storedPath + storedFileName;
    }

    return storedPath + "/" + storedFileName;
};

scwin.f_Retrieve = function() {
    let advcdGrpCd = scwin.getCurrentAdvcdGrpCd();

    if ($c.util.isEmpty(advcdGrpCd)) {
        $c.win.alert("그룹번호를 입력하세요.");
        ed_hhblno.focus();
        scwin.advcdGrpCd = "";
        scwin.f_CtrlStatus();
        scwin.f_clearFileList();
        return;
    }

    if ($c.util.isEmpty(scwin.seq)) {
        $c.win.alert("순번 정보가 없습니다.");
        scwin.f_clearFileList();
        return;
    }

    scwin.advcdGrpCd = advcdGrpCd;
    dma_attachedFile.set("advcdGrpCd", advcdGrpCd);
    dma_attachedFile.set("seq", scwin.seq);
    scwin.applyUploadSubDir(advcdGrpCd, scwin.seq);
    scwin.f_CtrlStatus();
    sbm_retrieveAttachedFileList.action = "/ac.fm.paymgnt.advcdmgnt.RetreiveAdvancedPaymentAttachFileListCMD.do?advcdGrpCd=" + encodeURIComponent(scwin.advcdGrpCd) + "&seq=" + encodeURIComponent(scwin.seq);
    $c.sbm.execute(sbm_retrieveAttachedFileList);
};

scwin.sbm_retrieveAttachedFileList_submitdone = function() {
    let fileList = [];

    for (let i = 0; i < ds_attachedFileList.getRowCount(); i++) {
        const fileName = ds_attachedFileList.getCellData(i, "fileName");
        const filePath = ds_attachedFileList.getCellData(i, "filePath");

        fileList.push({
            chk: "0",
            FILE_STORED_PATH: filePath,
            STORED_FILE_NM: fileName,
            ORIGIN_FILE_NM: fileName,
            FILE_EXPLAIN: "",
            FILE_SIZE: ds_attachedFileList.getCellData(i, "fileSize"),
            status: "Completed",
            hiddenKey: ds_attachedFileList.getCellData(i, "fileSeq")
        });
    }

    udc_fileUpload.setData(fileList);
    scwin.f_CtrlStatus();
};

scwin.sbm_retrieveImportFileList_submitdone = function() {
    if (ds_importFileList.getRowCount() < 1) {
        $c.win.alert("해당하는 첨부파일이 없습니다.");
        return;
    }

    scwin.buildImportSaveRows();
    scwin.pendingImportSave = true;
    $c.sbm.execute(sbm_saveFile);
};

scwin.f_clearFileList = function() {
    if (typeof udc_fileUpload !== "undefined") {
        udc_fileUpload.setData([]);
    }
    scwin.applyUploadSubDir("", "");
    scwin.f_CtrlStatus();
};

scwin.udc_fileUpload_onFileUploadDone = function (isSuccess) {
    if (!isSuccess) {
        return;
    }

    let advcdGrpCd = $c.str.trim($p, ed_hhblno.getValue());

    if ($c.util.isEmpty(advcdGrpCd)) {
        $c.win.alert("그룹번호가 필수입니다.");
        ed_hhblno.focus();
        return;
    }

    if ($c.util.isEmpty(scwin.seq)) {
        $c.win.alert("순번 정보가 없습니다.");
        return;
    }

    scwin.advcdGrpCd = advcdGrpCd;
    dma_attachedFile.set("advcdGrpCd", advcdGrpCd);
    dma_attachedFile.set("seq", scwin.seq);

    ds_fileUploadGDS.removeAll();

    let fileList = udc_fileUpload.getData() || [];

    for (let i = 0; i < fileList.length; i++) {
        if (fileList[i].status == "Completed" && $c.util.isEmpty(fileList[i].hiddenKey)) {
            let row = ds_fileUploadGDS.insertRow();
            ds_fileUploadGDS.setCellData(row, "advcdGrpCd", scwin.advcdGrpCd);
            ds_fileUploadGDS.setCellData(row, "seq", scwin.seq);
            ds_fileUploadGDS.setCellData(row, "fileClsCd", "");
            ds_fileUploadGDS.setCellData(row, "fileName", fileList[i].ORIGIN_FILE_NM);
            ds_fileUploadGDS.setCellData(row, "filePath", scwin.buildUploadFilePath(fileList[i].FILE_STORED_PATH, fileList[i].STORED_FILE_NM));
            ds_fileUploadGDS.setCellData(row, "fileSize", fileList[i].FILE_SIZE);
            ds_fileUploadGDS.setCellData(row, "regId", scwin.userId);
            ds_fileUploadGDS.setCellData(row, "modId", scwin.userId);
        }
    }

    if (ds_fileUploadGDS.getRowCount() > 0) {
        $c.sbm.execute(sbm_saveFile);
    } else if (ds_fileDeleteGDS.getRowCount() > 0) {
        $c.sbm.execute(sbm_deleteFile);
    } else {
        scwin.f_Retrieve();
    }
};

scwin.sbm_saveFile_submitdone = function() {
    if (scwin.pendingImportSave) {
        scwin.pendingImportSave = false;
        $c.gus.cfAlertMsg("파일 가져오기가 완료되었습니다.");
    }

    if (ds_fileDeleteGDS.getRowCount() > 0) {
        $c.sbm.execute(sbm_deleteFile);
    } else {
        scwin.f_Retrieve();
    }
};

scwin.sbm_deleteFile_submitdone = function() {
    ds_fileDeleteGDS.removeAll();
    scwin.f_Retrieve();
};

scwin.sbm_default_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.btn_remove_onclick = function (e) {
    ed_hhblno.setValue("");
    scwin.advcdGrpCd = "";
    scwin.f_CtrlStatus();
    scwin.f_clearFileList();
};
